    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FMETALBONE2026AleGalan_01.jpg%3Fv%3D1763726194&feedId=98176&k=8503cf1aa32c87ad6d2994520906e2323a444fbe",
