    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2F261985CoelloTourPadelBagL3200_1.jpg%3Fv%3D1758888633&feedId=98176&k=813fd79ebac34b2ac8f3fc02e554dd287282bcad",
