    "rating": null,
    "badge": null,
    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FGELRESOLUTION_1.jpg%3Fv%3D1768207443&feedId=98176&k=0f6d245fb03a3081c0fd71e394e0bfb5f8f83e67",
    "ean": "4571633405969",
