    "badge": null,
    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FMETALBONETEAMLIGHT_1.jpg%3Fv%3D1763727631&feedId=98176&k=c666a34a2defea560e6bd1ec41a388f690fbbbf0",
