    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FCOELLOTEAM_1.jpg%3Fv%3D1769675943&feedId=98176&k=c86080b0d47dfbe0872e1b1a62eb501411f3e1e1",
    "ean": "0198772152123",
    "productGTIN": null,
