    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FTECEHNICALVERON_1.jpg%3Fv%3D1768210762&feedId=98176&k=cb0af4be7251c9af3a091af46b925d3d67fb7c64",
