    "image": "https://images2.productserve.com/?w=200&h=200&bg=white&trim=5&t=letterbox&url=ssl%3Acdn.shopify.com%2Fs%2Ffiles%2F1%2F0646%2F3671%2F5163%2Ffiles%2FGELCHALLENGER14CLAY_1.jpg%3Fv%3D1765446118&feedId=98176&k=260ac7f1ec4a125a619eec41ff6b432731748ddc",
    "ean": "4550457386852",
